mapper.select:
/* com.erns.coching.code.mapper.CodeDAO.selectCodeList */
SELECT AA.CODE , AA.GRP_CODE , AA.CODE_NAME , AA.ETC1 , AA.ETC2 , AA.ETC3 , AA.ETC4 , AA.ETC5 , AA.CODE_DESC , AA.SORT_ORD , AA.USE_YN FROM T_CODE_INF AA JOIN T_CODE_MST CM ON AA.GRP_CODE = CM.GRP_CODE
ORDER BY AA.SORT_ORD

mapper.insert:
    	/* com.erns.coching.code.mapper.CodeDAO.insert */

    	INSERT INTO T_CODE_INF (
    		  CODE
				, GRP_CODE
				, CODE_NAME
			    , ETC1
			    , ETC2
			    , ETC3
			    , ETC4
			    , ETC5
				, CODE_DESC
				, SORT_ORD
				, USE_YN

				, RGTR
				, RGT_DTTM
				, CHNR
				, CHNG_DTTM
    	) VALUES (
					#{code	, jdbcType=VARCHAR}
				, #{grpCode	, jdbcType=VARCHAR}
				, #{codeName, jdbcType=VARCHAR}
				, #{etc1, jdbcType=VARCHAR}
				, #{etc2, jdbcType=VARCHAR}
				, #{etc3, jdbcType=VARCHAR}
				, #{etc4, jdbcType=VARCHAR}
				, #{etc5, jdbcType=VARCHAR}
				, #{codeDesc, jdbcType=VARCHAR}
				, (
					SELECT COALESCE(MAX(ZZ.SORT_ORD), 0) +1
					FROM T_CODE_INF ZZ
					WHERE ZZ.GRP_CODE = #{grpCode, jdbcType=VARCHAR}
				)
				, COALESCE(#{useYn		, jdbcType=CHAR}, 'Y')

				, #{rgtr	, jdbcType=INTEGER}
				, now()
				, #{chnr	, jdbcType=INTEGER}
				, now()
    	)

mapper.update:
    	/* com.erns.coching.code.mapper.CodeDAO.update */

    	UPDATE T_CODE_INF SET
					CODE_NAME  = #{codeName, jdbcType=VARCHAR}
				, ETC1  = #{etc1, jdbcType=VARCHAR}
				, ETC2  = #{etc2, jdbcType=VARCHAR}
				, ETC3  = #{etc3, jdbcType=VARCHAR}
				, ETC4  = #{etc4, jdbcType=VARCHAR}
				, ETC5  = #{etc5, jdbcType=VARCHAR}
				, CODE_DESC  = #{codeDesc	, jdbcType=VARCHAR}
				, SORT_ORD 	 = #{sortOrd	, jdbcType=INTEGER}
				, USE_YN 	 = #{useYn		, jdbcType=CHAR}

				, CHNR 		 = #{chnr	, jdbcType=INTEGER}
				, CHNG_DTTM  = now()

				AND CODE 	 = #{code	, jdbcType=VARCHAR}
				AND GRP_CODE = #{grpCode , jdbcType=VARCHAR}

    	/* com.erns.coching.code.mapper.CodeDAO.updateUseYn */

    	UPDATE T_CODE_INF SET
					USE_YN 	 = #{useYn	, jdbcType=CHAR}

				, CHNR 		 = #{chnr	, jdbcType=INTEGER}
				, CHNG_DTTM  = now()

				AND CODE 	 = #{code	, jdbcType=VARCHAR}
				AND GRP_CODE = #{grpCode , jdbcType=VARCHAR}

mapper.delete:
/* com.erns.coching.code.mapper.CodeDAO.delete */

DELETE FROM T_CODE_INF

	AND CODE 	 = #{code	, jdbcType=VARCHAR}
